#include <stdio.h>
#include <string.h>
#define MOD 1000000007
int main() {
    char s[100005];
    scanf("%s", s);
    int n = strlen(s);
    long long res = 0;
    for (int i = 0; i < n; i++) {
        for (char c = 'A'; c <= 'Z'; c++) {
            if (c > s[i]) {
                int j = n - 1 - i;
                if (j >= 0 && c >= s[j]) {
                    res = (res + 1) % MOD;
                }
            }
        }
    }
    printf("%lld\n", res);
    return 0;
}

